// Processar resposta do WhatsApp - Full Force Academia
const resposta = ($json.message || '').toLowerCase();
const telefone = $json.from || '';
const nome = $json.nome || 'Aluno';

// Analisar intenção da resposta
let interessado = false;
let categoria_resposta = 'NEUTRO';
let proxima_acao = 'AGUARDAR';

// Respostas positivas
if (resposta.includes('sim') || resposta.includes('quero') || resposta.includes('interessado') || resposta.includes('vamos') || resposta.includes('aceito')) {
  interessado = true;
  categoria_resposta = 'INTERESSADO';
  proxima_acao = 'CONTATAR_VENDAS';
}

// Respostas negativas
else if (resposta.includes('não') || resposta.includes('nao') || resposta.includes('desinteressado') || resposta.includes('pare') || resposta.includes('remover')) {
  interessado = false;
  categoria_resposta = 'RECUSOU';
  proxima_acao = 'REMOVER_LISTA';
}

// Dúvidas/perguntas
else if (resposta.includes('?') || resposta.includes('como') || resposta.includes('quanto') || resposta.includes('horário') || resposta.includes('valor')) {
  interessado = true;
  categoria_resposta = 'DUVIDAS';
  proxima_acao = 'RESPONDER_DUVIDAS';
}

const resultado = {
  telefone: telefone,
  nome: nome,
  resposta_original: $json.message || '',
  interessado: interessado,
  categoria_resposta: categoria_resposta,
  proxima_acao: proxima_acao,
  data_resposta: new Date().toISOString(),
  academia: 'Full Force Academia',
  cidade: 'Matupá-MT'
};

console.log('📱 [WHATSAPP RESPONSE] Processando:', nome, telefone);
console.log('💬 [RESPOSTA]:', resposta);
console.log('🎯 [CATEGORIA]:', categoria_resposta);
console.log('⚡ [AÇÃO]:', proxima_acao);

return resultado;
